from dataclasses import dataclass
from datetime import datetime

@dataclass
class UptimeMeasurement:
    """Track uptime according to a specific SLA definition."""
    month_start: datetime
    month_end: datetime
    # Each entry: (minute_start, error_count, request_count)
    minute_samples: list[tuple[datetime, int, int]]
    # Contract parameters
    error_threshold_pct: float = 1.0    # 100% errors = downtime minute
    consecutive_minutes_required: int = 1

    @property
    def total_minutes(self) -> int:
        delta = self.month_end - self.month_start
        return int(delta.total_seconds() / 60)

    def downtime_minutes(self) -> int:
        count = 0
        consecutive = 0
        for _, errors, requests in self.minute_samples:
            if requests == 0:
                consecutive = 0
                continue
            error_rate = errors / requests
            if error_rate >= self.error_threshold_pct:
                consecutive += 1
                if consecutive >= self.consecutive_minutes_required:
                    count += 1
            else:
                consecutive = 0
        return count

    def uptime_pct(self) -> float:
        down = self.downtime_minutes()
        return (self.total_minutes - down) / self.total_minutes * 100

    def sla_breached(self, contracted_pct: float) -> bool:
        return self.uptime_pct() < contracted_pct

