from datetime import datetime
from collections import defaultdict

class SLAProbe:
    """
    Lightweight probe that tracks uptime and latency for SLA reporting.
    Run as a sidecar to your API gateway.
    """
    def __init__(self, vendor: str, model: str):
        self.vendor = vendor
        self.model = model
        # minute_bucket → {"requests": int, "errors": int, "ttft_ms": list[float]}
        self.buckets: dict[str, dict] = defaultdict(lambda: {"requests": 0, "errors": 0, "ttft_ms": []})

    def _bucket_key(self) -> str:
        return datetime.utcnow().strftime("%Y-%m-%dT%H:%M")

    def record(self, status_code: int, ttft_ms: float | None) -> None:
        key = self._bucket_key()
        self.buckets[key]["requests"] += 1
        if status_code >= 500:
            self.buckets[key]["errors"] += 1
        if ttft_ms is not None:
            self.buckets[key]["ttft_ms"].append(ttft_ms)

    def monthly_uptime(self, year: int, month: int) -> float:
        prefix = f"{year:04d}-{month:02d}"
        total, downtime = 0, 0
        for key, data in self.buckets.items():
            if not key.startswith(prefix):
                continue
            total += 1
            if data["requests"] > 0:
                err_rate = data["errors"] / data["requests"]
                if err_rate >= 0.5:
                    downtime += 1
        return (total - downtime) / total * 100 if total else 100.0

import time
from enum import Enum
from dataclasses import dataclass, field

class CircuitState(Enum):
    CLOSED = "closed"       # Normal operation
    OPEN = "open"           # Failing; requests blocked or rerouted
    HALF_OPEN = "half_open" # Probing recovery

@dataclass
class CircuitBreaker:
    name: str
    failure_threshold: int = 5       # Open after N failures in window
    recovery_timeout_s: float = 30.0 # Try again after this many seconds
    success_threshold: int = 2       # Close after N consecutive successes

    _failures: int = field(default=0, repr=False)
    _state: CircuitState = field(default=CircuitState.CLOSED, repr=False)
    _opened_at: float | None = field(default=None, repr=False)
    _probe_successes: int = field(default=0, repr=False)

    def record_success(self) -> None:
        if self._state == CircuitState.HALF_OPEN:
            self._probe_successes += 1
            if self._probe_successes >= self.success_threshold:
                self._state = CircuitState.CLOSED
                self._failures = 0
                self._probe_successes = 0
        elif self._state == CircuitState.CLOSED:
            self._failures = max(0, self._failures - 1)

    def record_failure(self) -> None:
        self._failures += 1
        if self._failures >= self.failure_threshold:
            self._state = CircuitState.OPEN
            self._opened_at = time.monotonic()

    def allow_request(self) -> bool:
        if self._state == CircuitState.CLOSED:
            return True
        if self._state == CircuitState.OPEN:
            if self._opened_at and time.monotonic() - self._opened_at >= self.recovery_timeout_s:
                self._state = CircuitState.HALF_OPEN
                self._probe_successes = 0
                return True
            return False
        # HALF_OPEN: allow one probe at a time
        return self._probe_successes == 0

# Usage: wrap each LLM vendor in a circuit breaker
primary_cb = CircuitBreaker(name="openai-primary")
backup_cb = CircuitBreaker(name="anthropic-backup")

def call_with_failover(prompt: str) -> str:
    for cb, vendor_fn in [(primary_cb, call_openai), (backup_cb, call_anthropic)]:
        if not cb.allow_request():
            continue
        try:
            result = vendor_fn(prompt)
            cb.record_success()
            return result
        except Exception:
            cb.record_failure()
    raise RuntimeError("All vendors unavailable")

